// Report index page functionality

// GitHub repository information - will be updated dynamically
const REPO_OWNER = 'your-username';  // Replace with actual username
const REPO_NAME = 'stock_analyzer';
const REPORTS_PATH = 'docs/reports';

// Fetch reports list from GitHub API
async function fetchReports() {
    const container = document.getElementById('reports-container');
    
    try {
        // Try to fetch from GitHub API
        const apiUrl = `https://api.github.com/repos/${REPO_OWNER}/${REPO_NAME}/contents/${REPORTS_PATH}`;
        const response = await fetch(apiUrl);
        
        if (!response.ok) {
            throw new Error('GitHub API failed');
        }
        
        const files = await response.json();
        
        // Filter HTML files and sort by date (newest first)
        const reports = files
            .filter(file => file.name.endsWith('.html') && file.name.startsWith('report_'))
            .map(file => {
                // Extract date from filename (report_YYYYMMDD_HHMMSS.html)
                const match = file.name.match(/report_(\d{8})_(\d{6})\.html/);
                let date = null;
                let displayDate = file.name;
                
                if (match) {
                    const dateStr = match[1];
                    const timeStr = match[2];
                    date = new Date(
                        parseInt(dateStr.substr(0, 4)),
                        parseInt(dateStr.substr(4, 2)) - 1,
                        parseInt(dateStr.substr(6, 2)),
                        parseInt(timeStr.substr(0, 2)),
                        parseInt(timeStr.substr(2, 2)),
                        parseInt(timeStr.substr(4, 2))
                    );
                    displayDate = date.toLocaleString('zh-TW', {
                        year: 'numeric',
                        month: '2-digit',
                        day: '2-digit',
                        hour: '2-digit',
                        minute: '2-digit'
                    });
                }
                
                return {
                    name: file.name,
                    path: file.path.replace('docs/', ''),
                    date: date,
                    displayDate: displayDate,
                    url: file.download_url
                };
            })
            .sort((a, b) => {
                if (!a.date || !b.date) return 0;
                return b.date - a.date;
            });
        
        updateStats(reports);
        displayReports(reports);
        
    } catch (error) {
        console.error('Error fetching reports:', error);
        // Fallback: try to load from local reports.json
        loadFromJSON();
    }
}

// Load from local reports.json (generated by generate_index.py)
async function loadFromJSON() {
    try {
        const response = await fetch('reports/reports.json');
        if (!response.ok) {
            throw new Error('No reports.json');
        }
        
        const data = await response.json();
        const reports = data.reports || [];
        
        updateStats(reports);
        displayReports(reports);
        
    } catch (error) {
        console.error('Error loading from JSON:', error);
        showNoReports();
    }
}

// Update statistics
function updateStats(reports) {
    document.getElementById('total-reports').textContent = reports.length;
    
    if (reports.length > 0) {
        const latest = reports[0];
        document.getElementById('latest-report').textContent = latest.displayDate || latest.name;
    }
}

// Display reports list
function displayReports(reports) {
    const container = document.getElementById('reports-container');
    
    if (reports.length === 0) {
        showNoReports();
        return;
    }
    
    container.innerHTML = reports.map(report => `
        <div class="report-item">
            <div class="report-info">
                <h3>📊 分析報告</h3>
                <div class="date">${report.displayDate || report.name}</div>
            </div>
            <a href="${report.path || report.url}" target="_blank">查看報告</a>
        </div>
    `).join('');
}

// Show no reports message
function showNoReports() {
    const container = document.getElementById('reports-container');
    container.innerHTML = `
        <div class="no-reports">
            <p>📭 目前還沒有報告</p>
            <p style="margin-top: 10px; font-size: 0.9em;">
                報告將在每日 07:00 (HKT) 自動生成
            </p>
        </div>
    `;
}

// Search functionality
document.getElementById('search').addEventListener('input', (e) => {
    const searchTerm = e.target.value.toLowerCase();
    const reportItems = document.querySelectorAll('.report-item');
    
    reportItems.forEach(item => {
        const text = item.textContent.toLowerCase();
        item.style.display = text.includes(searchTerm) ? 'flex' : 'none';
    });
});

// Initialize
document.addEventListener('DOMContentLoaded', () => {
    // Try GitHub API first, fallback to JSON
    fetchReports().catch(() => loadFromJSON());
});
